import { Download } from "lucide-react";
import { Button } from "./ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "./ui/card";

const FILE_B64 = "";

export function Descarga() {
  const handleDownload = () => {
    const binary = atob(FILE_B64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    const blob = new Blob([bytes], { type: "application/gzip" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "fidelizacion-proyecto.tar.gz";
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="flex items-center justify-center min-h-[70vh]">
      <Card className="max-w-md w-full">
        <CardHeader className="text-center">
          <div className="text-5xl mb-4">📦</div>
          <CardTitle className="text-2xl">Descargar Proyecto</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4 text-center">
          <p className="text-muted-foreground">
            Sistema de Fidelización — Frontend React + Backend Express
          </p>
          <ul className="text-sm text-left space-y-1 text-muted-foreground">
            <li>✅ Componentes React con TypeScript</li>
            <li>✅ Backend Express con 21 endpoints REST</li>
            <li>✅ Capa de servicios HTTP</li>
            <li>✅ Persistencia con localStorage</li>
            <li>✅ Exportación de reportes como imagen</li>
          </ul>
          <Button onClick={handleDownload} className="w-full mt-4" size="lg">
            <Download className="mr-2 size-5" />
            Descargar .tar.gz (~104 KB)
          </Button>
          <p className="text-xs text-muted-foreground">
            Sin node_modules. Ejecutar: <code className="bg-muted px-1 rounded">pnpm install &amp;&amp; pnpm start</code>
          </p>
        </CardContent>
      </Card>
    </div>
  );
}
